const maxAgeMs = 30 * 24 * 60 * 60 * 1000;
const now = Date.now();

const sources = [
  { provider: 'openai', source_name: 'OpenAI News', url: 'https://openai.com/news/rss.xml', type: 'rss' },
  { provider: 'anthropic', source_name: 'Anthropic Release Notes', url: 'https://platform.claude.com/docs/en/release-notes/overview', type: 'anthropic-release-notes' },
  { provider: 'google', source_name: 'Google AI Blog', url: 'https://blog.google/innovation-and-ai/technology/ai/rss/', type: 'rss' },
];

function stripTags(value) {
  return String(value || '')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function firstMatch(text, patterns) {
  for (const pattern of patterns) {
    const match = String(text || '').match(pattern);
    if (match) return stripTags(match[1] || match[0]);
  }
  return '';
}

function slugify(value) {
  return String(value || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 90) || 'model-release';
}

function yamlString(value) {
  const safe = String(value || '').replace(/\\/g, '\\\\').replace(/"/g, '\\"');
  return '"' + safe + '"';
}

function parseRss(xml, source) {
  const itemMatches = Array.from(String(xml || '').matchAll(/<item[\s\S]*?<\/item>/gi));
  return itemMatches.map((match) => {
    const item = match[0];
    const title = firstMatch(item, [/<title><!\[CDATA\[([\s\S]*?)\]\]><\/title>/i, /<title>([\s\S]*?)<\/title>/i]);
    const link = firstMatch(item, [/<link>([\s\S]*?)<\/link>/i]);
    const pubDate = firstMatch(item, [/<pubDate>([\s\S]*?)<\/pubDate>/i, /<dc:date>([\s\S]*?)<\/dc:date>/i]);
    const excerpt = firstMatch(item, [/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>/i, /<description>([\s\S]*?)<\/description>/i, /<content:encoded><!\[CDATA\[([\s\S]*?)\]\]><\/content:encoded>/i]);
    return { provider: source.provider, source_name: source.source_name, source_type: 'primaire', category: 'model-release', signal_type: 'model-release', title, url: link || source.url, published_at: pubDate ? new Date(pubDate).toISOString() : new Date().toISOString(), raw_excerpt: excerpt, source_url: source.url };
  });
}

function parseAnthropicReleaseNotes(html, source) {
  const text = stripTags(html);
  const datePattern = /(\d{1,2}\s+(?:January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{4})/gi;
  const dates = Array.from(text.matchAll(datePattern)).map((m) => ({ date: m[1], index: m.index || 0 }));
  const entries = [];
  for (let i = 0; i < dates.length; i++) {
    const current = dates[i];
    const next = dates[i + 1];
    const chunk = text.slice(current.index, next ? next.index : current.index + 1400);
    const modelMatch = chunk.match(/\bClaude\s+(?:Opus|Sonnet|Haiku)\s+\d(?:\.\d)?\b/i);
    if (!modelMatch) continue;
    const model = modelMatch[0];
    entries.push({ provider: source.provider, source_name: source.source_name, source_type: 'primaire', category: 'model-release', signal_type: 'model-release', title: model + ' release notes', url: source.url, published_at: new Date(current.date).toISOString(), raw_excerpt: chunk.slice(0, 1200), source_url: source.url });
  }
  return entries;
}

function isRelevantModelSignal(item) {
  const body = item.title + ' ' + item.raw_excerpt;
  const modelPatterns = { openai: /\b(GPT[- ]?\d(?:\.\d)?|gpt[- ]?\d(?:\.\d)?|o\d(?:[- ]?pro)?|model|models)\b/i, anthropic: /\b(Claude|Opus|Sonnet|Haiku|model|models)\b/i, google: /\b(Gemini\s*\d(?:\.\d)?|Gemini|Flash|Pro|Ultra|TTS|model|models)\b/i };
  const exclude = /\b(Codex|CLI|SDK|Agents SDK|Cloudflare|operations teams|academy|customer story|partnership|workflows in|trusted access for cyber)\b/i;
  if (!modelPatterns[item.provider] || !modelPatterns[item.provider].test(body)) return false;
  if (item.provider !== 'google' && exclude.test(body)) return false;
  if (item.provider === 'google' && /\b(Google Vids|satellite imagery|forests)\b/i.test(body)) return false;
  return true;
}

function inferModelFamily(item) {
  const body = item.title + ' ' + item.raw_excerpt;
  const match = body.match(/\b(GPT[- ]?\d(?:\.\d)?(?:[- ]?[A-Za-z]+)?|Claude\s+(?:Opus|Sonnet|Haiku)\s+\d(?:\.\d)?|Gemini\s*\d(?:\.\d)?\s*(?:Flash|Pro|Ultra|TTS)?|Gemini\s*(?:Flash|Pro|Ultra|TTS)|o\d(?:[- ]?pro)?)\b/i);
  return match ? match[0].replace(/\s+/g, ' ').trim() : item.provider;
}

function buildMarkdown(item) {
  const collectedAt = new Date().toISOString();
  const publishedDate = String(item.published_at || collectedAt).slice(0, 10);
  const modelFamily = inferModelFamily(item);
  const provider = item.provider;
  const title = stripTags(item.title).slice(0, 240);
  const excerpt = stripTags(item.raw_excerpt || '').slice(0, 1400) || 'Aucun extrait disponible.';
  const fileName = publishedDate + '-' + slugify(provider + '-model-release') + '-' + slugify(title) + '.md';
  const outputPath = '/vault/raw/passive/model/' + fileName;
  const tags = ['ia', provider, 'model-release'];
  const markdown = [
    '---', 'kind: passive-capture', 'source_name: ' + yamlString(item.source_name), 'source_type: primaire', 'category: model-release', 'provider: ' + provider, 'model_family: ' + yamlString(modelFamily), 'signal_type: model-release', 'tags: [' + tags.join(', ') + ']', 'title: ' + yamlString(title), 'url: ' + yamlString(item.url), 'published_at: ' + yamlString(item.published_at), 'collected_at: ' + yamlString(collectedAt), 'confidence: high', 'major_update: true', 'workflow: passive-model-releases', 'status: a-traiter', '---', '', '# ' + title, '', '## Metadonnees', '- Provider : ' + provider, '- Source : ' + item.source_name, '- Type : primaire', '- Categorie : model-release', '- Famille modele : ' + modelFamily, '- URL : ' + item.url, '- Publie le : ' + item.published_at, '- Collecte le : ' + collectedAt, '', '## Extrait brut', excerpt, '', '## Resume IA preliminaire', '- Signal de modele detecte pour ' + provider + '.', '- Famille ou modele probable : ' + modelFamily + '.', '- A verifier avant incorporation dans une note provider ou modeles-ia.', '', '## Points a verifier', '- Confirmer que l annonce concerne bien un modele ou une famille de modeles, et pas seulement un produit.', '- Verifier les capacites, disponibilites, tarifs ou deprecations mentionnes par la source officielle.', '- Decider si la note provider doit etre mise a jour.', '', '## Action possible', '- [ ] Decider si cette entree merite une mise a jour dans wiki/notes/openai.md, wiki/notes/anthropic.md, wiki/notes/gemini.md ou wiki/notes/modeles-ia.md', ''
  ].join('\n');
  return Object.assign({}, item, { model_family: modelFamily, fileName, outputPath, markdown });
}

async function fetchText(url) {
  const response = await fetch(url, { headers: { 'User-Agent': 'veille-obsidian-model-releases/1.0', 'Accept': 'text/html,application/rss+xml,application/xml,text/xml,*/*' } });
  if (!response.ok) throw new Error('Fetch failed ' + response.status + ' for ' + url);
  return response.text();
}

const fetched = [];
for (const source of sources) {
  try {
    const content = await fetchText(source.url);
    if (source.type === 'rss') fetched.push(...parseRss(content, source));
    if (source.type === 'anthropic-release-notes') fetched.push(...parseAnthropicReleaseNotes(content, source));
  } catch (error) {}
}

const candidates = fetched.filter((item) => item.title && item.url).filter((item) => { const published = Date.parse(item.published_at || ''); return Number.isNaN(published) || now - published <= maxAgeMs; }).filter(isRelevantModelSignal).sort((a, b) => Date.parse(b.published_at || 0) - Date.parse(a.published_at || 0));
const byProvider = new Map();
for (const item of candidates) if (!byProvider.has(item.provider)) byProvider.set(item.provider, item);
return Array.from(byProvider.values()).map((item) => ({ json: buildMarkdown(item) }));
